330   const SCEV *BTC = SE.getBackedgeTakenCount(&L);
331   Value *Inc;
332   CmpPredicate Pred;
333   BasicBlock *Succ1;
334   BasicBlock *Succ2;
335   // The loop must execute at least 2 iterations to guarantee that peeled
336   // iteration executes.
337   // TODO: Add checks during codegen.
338   if (isa<SCEVCouldNotCompute>(BTC) ||
339       !SE.isKnownPredicate(CmpInst::ICMP_UGT, BTC, SE.getZero(BTC->getType())))
340     return false;
