401   // Increase PeelCount while (IterVal Pred BoundSCEV) condition is satisfied;
402   // return true if inversed condition become known before reaching the
403   // MaxPeelCount limit.
404   auto PeelWhilePredicateIsKnown =
405       [&](unsigned &PeelCount, const SCEV *&IterVal, const SCEV *BoundSCEV,
406           const SCEV *Step, ICmpInst::Predicate Pred) {
407         while (PeelCount < MaxPeelCount &&
408                SE.isKnownPredicate(Pred, IterVal, BoundSCEV)) {
409           IterVal = SE.getAddExpr(IterVal, Step);
410           ++PeelCount;
411         }
412         return SE.isKnownPredicate(ICmpInst::getInversePredicate(Pred), IterVal,
413                                    BoundSCEV);
414       };
415 
416   const unsigned MaxDepth = 4;
417   std::function<void(Value *, unsigned)> ComputePeelCount =
418       [&](Value *Condition, unsigned Depth) -> void {
419     if (!Condition->getType()->isIntegerTy() || Depth >= MaxDepth)
420       return;
421 
422     Value *LeftVal, *RightVal;
423     if (match(Condition, m_And(m_Value(LeftVal), m_Value(RightVal))) ||
424         match(Condition, m_Or(m_Value(LeftVal), m_Value(RightVal)))) {
425       ComputePeelCount(LeftVal, Depth + 1);
426       ComputePeelCount(RightVal, Depth + 1);
427       return;
428     }
429 
430     CmpPredicate Pred;
431     if (!match(Condition, m_ICmp(Pred, m_Value(LeftVal), m_Value(RightVal))))
432       return;
433 
434     const SCEV *LeftSCEV = SE.getSCEV(LeftVal);
435     const SCEV *RightSCEV = SE.getSCEV(RightVal);
436 
437     // Do not consider predicates that are known to be true or false
438     // independently of the loop iteration.
439     if (SE.evaluatePredicate(Pred, LeftSCEV, RightSCEV))
440       return;
441 
442     // Check if we have a condition with one AddRec and one non AddRec
443     // expression. Normalize LeftSCEV to be the AddRec.
444     if (!isa<SCEVAddRecExpr>(LeftSCEV)) {
445       if (isa<SCEVAddRecExpr>(RightSCEV)) {
446         std::swap(LeftSCEV, RightSCEV);
447         Pred = ICmpInst::getSwappedPredicate(Pred);
