683                         << " iteration(s) to turn"
684                         << " some Phis into invariants.\n");
685       PP.PeelCount = DesiredPeelCountLast;
686       PP.PeelProfiledIterations = false;
687       PP.PeelLast = true;
688       return;
689     }
690   }
691 
692   // Bail if we know the statically calculated trip count.
693   // In this case we rather prefer partial unrolling.
694   if (TripCount)
695     return;
696 
697   // Do not apply profile base peeling if it is disabled.
698   if (!PP.PeelProfiledIterations)
699     return;
700   // If we don't know the trip count, but have reason to believe the average
