 750 static void updateBranchWeights(Instruction *Term, WeightInfo &Info) {
 751   setBranchWeights(*Term, Info.Weights, /*IsExpected=*/false);
 752   for (auto [Idx, SubWeight] : enumerate(Info.SubWeights))
 753     if (SubWeight != 0)
 754       // Don't set the probability of taking the edge from latch to loop header
 755       // to less than 1:1 ratio (meaning Weight should not be lower than
 756       // SubWeight), as this could significantly reduce the loop's hotness,
 757       // which would be incorrect in the case of underestimating the trip count.
 758       Info.Weights[Idx] =
 759           Info.Weights[Idx] > SubWeight
 760               ? std::max(Info.Weights[Idx] - SubWeight, SubWeight)
 761               : SubWeight;
 762 }
 763 
 764 /// Initialize the weights for all exiting blocks.
 765 static void initBranchWeights(DenseMap<Instruction *, WeightInfo> &WeightInfos,
 766                               Loop *L) {
 767   SmallVector<BasicBlock *> ExitingBlocks;
 768   L->getExitingBlocks(ExitingBlocks);
 769   for (BasicBlock *ExitingBlock : ExitingBlocks) {
 770     Instruction *Term = ExitingBlock->getTerminator();
 771     SmallVector<uint32_t> Weights;
 772     if (!extractBranchWeights(*Term, Weights))
 773       continue;
 774 
 775     // See the comment on updateBranchWeights() for an explanation of what we
 776     // do here.
 777     uint32_t FallThroughWeights = 0;
 778     uint32_t ExitWeights = 0;
 779     for (auto [Succ, Weight] : zip(successors(Term), Weights)) {
 780       if (L->contains(Succ))
 781         FallThroughWeights += Weight;
 782       else
 783         ExitWeights += Weight;
 784     }
 785 
 786     // Don't try to update weights for degenerate case.
 787     if (FallThroughWeights == 0)
 788       continue;
 789 
 790     SmallVector<uint32_t> SubWeights;
 791     for (auto [Succ, Weight] : zip(successors(Term), Weights)) {
 792       if (!L->contains(Succ)) {
 793         // Exit weights stay the same.
 794         SubWeights.push_back(0);
 795         continue;
 796       }
 797 
 798       // Subtract exit weights on each iteration, distributed across all
 799       // fallthrough edges.
 800       double W = (double)Weight / (double)FallThroughWeights;
 801       SubWeights.push_back((uint32_t)(ExitWeights * W));
 802     }
 803 
 804     WeightInfos.insert({Term, {std::move(Weights), std::move(SubWeights)}});
 805   }
 806 }
