 836   // For each block in the original loop, create a new copy,
 837   // and update the value map with the newly created values.
 838   for (LoopBlocksDFS::RPOIterator BB = BlockBegin; BB != BlockEnd; ++BB) {
 839     BasicBlock *NewBB = CloneBasicBlock(*BB, VMap, ".peel", F);
 840     NewBlocks.push_back(NewBB);
