 842     // If an original block is an immediate child of the loop L, its copy
 843     // is a child of a ParentLoop after peeling. If a block is a child of
 844     // a nested loop, it is handled in the cloneLoop() call below.
 845     if (ParentLoop && LI->getLoopFor(*BB) == L)
 846       ParentLoop->addBasicBlockToLoop(NewBB, *LI);
