 909   // that pick an incoming value from either the preheader, or the previous
 910   // loop iteration. Since this copy is no longer part of the loop, we
 911   // resolve this statically:
 912   if (PeelLast) {
 913     // For the last iteration, we use the value from the latch of the original
 914     // loop directly.
 915     for (BasicBlock::iterator I = Header->begin(); isa<PHINode>(I); ++I) {
 916       PHINode *NewPHI = cast<PHINode>(VMap[&*I]);
 917       VMap[&*I] = NewPHI->getIncomingValueForBlock(Latch);
 918       NewPHI->eraseFromParent();
 919     }
 920   } else {
 921     // For the first iteration, we use the value from the preheader directly.
 922     // For any other iteration, we replace the phi with the value generated by
 923     // the immediately preceding clone of the loop body (which represents
 924     // the previous iteration).
 925     for (BasicBlock::iterator I = Header->begin(); isa<PHINode>(I); ++I) {
